use prompty::model::TurnOptions;
use prompty::model::context::{LoadContext, SaveContext};

#[test]
fn test_turn_options_load_json() {
    let json = r####"
{
  "maxIterations": 10,
  "maxLlmRetries": 3,
  "contextBudget": 100000,
  "parallelToolCalls": true,
  "raw": false,
  "turn": 1,
  "compaction": {
    "strategy": "summarize"
  }
}
"####;
    let ctx = LoadContext::default();
    let result = TurnOptions::from_json(json, &ctx);
    assert!(result.is_ok(), "Failed to load from JSON: {:?}", result.err());
    let instance = result.unwrap();
    assert!(instance.max_iterations.is_some(), "Expected max_iterations to be Some");
    assert_eq!(instance.max_iterations.as_ref().unwrap(), &10);
    assert!(instance.max_llm_retries.is_some(), "Expected max_llm_retries to be Some");
    assert_eq!(instance.max_llm_retries.as_ref().unwrap(), &3);
    assert!(instance.context_budget.is_some(), "Expected context_budget to be Some");
    assert_eq!(instance.context_budget.as_ref().unwrap(), &100000);
    assert!(instance.parallel_tool_calls.is_some(), "Expected parallel_tool_calls to be Some");
    assert_eq!(instance.parallel_tool_calls.as_ref().unwrap(), &true);
    assert!(instance.raw.is_some(), "Expected raw to be Some");
    assert_eq!(instance.raw.as_ref().unwrap(), &false);
    assert!(instance.turn.is_some(), "Expected turn to be Some");
    assert_eq!(instance.turn.as_ref().unwrap(), &1);
}

